mapper.delete:
/* wms-file-sql-oracle.xml -deleteFileInfo */
	DELETE FROM TWORK_INFO_FILE
	 WHERE CTKEY = #{ctkey}
	   AND FILEKEY = #{filekey}
	   AND FILESEQNO = #{fileseqno}

mapper.insert:
/* wms-file-sql-oracle.xml - insertFileInfo */
	INSERT INTO TWORK_INFO_FILE
	(
			  CTKEY
			, FILEKEY
			, FILESEQNO
			, FILEPATH
			, FILESIZE
			, FILEEXTS
			, ORGFILENM
			, SAVFILENM
			, CMT
			, INSERTDATE
			, INSERTURKEY
			, UPDATEDATE
			, UPDATEURKEY
	)
	VALUES
	(
			  #{ctkey}
			, #{filekey}
			, #{fileseqno}
			, #{filepath}
			, #{filesize}
			, #{fileexts}
			, #{orgfilenm}
			, #{savfilenm}
			, #{cmt}
			, #{sysdate}
			, #{surkey}
			, #{sysdate}
			, #{surkey}
	)
